export default async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }
  try {
    const { name = "", email = "", package = "", message = "" } = req.body || {};
    if (!email || !email.includes("@")) {
      return res.status(400).json({ error: "Valid email required" });
    }

    // Persist to a known webhook so the AI thread picks it up.
    const ticket = {
      id: `tkt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      name, email, package, message,
      receivedAt: new Date().toISOString(),
    };

    console.log("CONTACT", JSON.stringify(ticket));

    // Reply immediately with a receipt page
    res.status(200).json({
      ok: true,
      ticket,
      next_steps: [
        "Within 24h we reply with a contract and quote",
        "Pay via Stripe link (you will receive it in the email)",
        "We deliver v1 within 7 days, with one round of revisions",
      ],
    });
  } catch (e) {
    res.status(500).json({ error: "Bad request" });
  }
}
